import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { FiPlus, FiEye, FiEdit2, FiTrash2 } from 'react-icons/fi';

const PimEmployeeList = () => {
  const [employees, setEmployees] = useState([]);
  const [search, setSearch] = useState('');
  const navigate = useNavigate();

  useEffect(() => { fetchEmployees(); }, []);

  const fetchEmployees = async (q) => {
    const params = q ? { search: q } : {};
    const { data } = await api.get('/pim/employees', { params });
    setEmployees(data);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this employee?')) {
      await api.delete(`/pim/employees/${id}`);
      fetchEmployees();
    }
  };

  return (
    <div>
      <div className="toolbar">
        <div className="search-box">
          <input placeholder="Search by name or ID..." value={search} onChange={e => { setSearch(e.target.value); fetchEmployees(e.target.value); }} />
        </div>
        <div className="toolbar-right">
          <button className="btn btn-primary" onClick={() => navigate('/pim/add')}><FiPlus /> Add Employee</button>
        </div>
      </div>
      <div className="card">
        <div className="card-header"><h3>Employee List</h3><span style={{ color: '#999', fontSize: 13 }}>{employees.length} records</span></div>
        <div className="card-body">
          <div className="table-container">
            <table>
              <thead><tr><th>ID</th><th>Name</th><th>Job Title</th><th>Department</th><th>Email</th><th>Status</th><th>Actions</th></tr></thead>
              <tbody>
                {employees.map(emp => (
                  <tr key={emp._id}>
                    <td>{emp.employeeId}</td>
                    <td><strong>{emp.fullName}</strong></td>
                    <td>{emp.jobTitle?.title || '-'}</td>
                    <td>{emp.department || '-'}</td>
                    <td>{emp.workEmail || '-'}</td>
                    <td><span className={`status-badge ${emp.isActive ? 'status-approved' : 'status-rejected'}`}>{emp.isActive ? 'Active' : 'Inactive'}</span></td>
                    <td>
                      <button className="action-btn" onClick={() => navigate(`/pim/${emp._id}`)}><FiEye /></button>
                      <button className="action-btn" onClick={() => navigate(`/pim/${emp._id}`)}><FiEdit2 /></button>
                      <button className="action-btn" onClick={() => handleDelete(emp._id)}><FiTrash2 /></button>
                    </td>
                  </tr>
                ))}
                {employees.length === 0 && (
                  <tr><td colSpan={7} style={{ textAlign: 'center', color: '#999', padding: 24 }}>No employees found</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PimEmployeeList;
